// app/layout.js
'use client';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import './globals.css';

export default function RootLayout({ children }) {
  const { user } = useAuth();
  const router = useRouter();

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (!error) router.push('/auth');
  };

  return (
    <html lang="en">
      <body className="bg-gray-100 text-black">
        {/* Shared Nav Bar */}
        <nav className="bg-white shadow p-4 flex justify-between items-center">
          <div className="text-xl font-bold text-purple-600">Creative Justice</div>
          {user && (
            <div className="flex gap-4 items-center">
              <button onClick={() => router.push('/feed')} className="hover:underline">Home</button>
              <button onClick={() => router.push('/my_network')} className="hover:underline">My Network</button>
              <button onClick={() => router.push('/profile')} className="hover:underline">Profile</button>
              <button onClick={handleLogout} className="text-red-500 hover:underline">Log Out</button>
            </div>
          )}
        </nav>

        {/* Page Content */}
        <main className="p-6 max-w-7xl mx-auto">{children}</main>
      </body>
    </html>
  );
}
